import{_ as d,o as e,c as a,ai as r}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"48 音标与发音入门","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/phonetics-48.md","filePath":"english-speaking/phonetics-48.md"}'),o={name:"english-speaking/phonetics-48.md"};function c(h,t,i,l,n,s){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_48-音标与发音入门" tabindex="-1">48 音标与发音入门 <a class="header-anchor" href="#_48-音标与发音入门" aria-label="Permalink to “48 音标与发音入门”">​</a></h1><blockquote><p>这一篇先帮你把英语发音基础搭起来。<br> 不求一次记死，但至少要知道：<strong>这个音标怎么读、和哪个汉语发音接近、容易错在哪里</strong>。</p></blockquote><hr><h2 id="一、元音-20" tabindex="-1">一、元音（20） <a class="header-anchor" href="#一、元音-20" aria-label="Permalink to “一、元音（20）”">​</a></h2><h3 id="单元音-12" tabindex="-1">单元音（12） <a class="header-anchor" href="#单元音-12" aria-label="Permalink to “单元音（12）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>大致感觉</th><th>例词</th></tr></thead><tbody><tr><td>/iː/</td><td>长音“衣”</td><td><code>see</code></td></tr><tr><td>/ɪ/</td><td>短促“衣”</td><td><code>sit</code></td></tr><tr><td>/e/</td><td>类似“诶”</td><td><code>bed</code></td></tr><tr><td>/æ/</td><td>张口更大</td><td><code>cat</code></td></tr><tr><td>/ɑː/</td><td>长音“啊”</td><td><code>car</code></td></tr><tr><td>/ɒ/</td><td>英式短“奥”</td><td><code>hot</code></td></tr><tr><td>/ɔː/</td><td>长音“哦”</td><td><code>door</code></td></tr><tr><td>/ʊ/</td><td>短促“乌”</td><td><code>book</code></td></tr><tr><td>/uː/</td><td>长音“乌”</td><td><code>food</code></td></tr><tr><td>/ʌ/</td><td>短“啊”</td><td><code>cup</code></td></tr><tr><td>/ɜː/</td><td>卷舌中间音</td><td><code>bird</code></td></tr><tr><td>/ə/</td><td>轻读“呃”</td><td><code>about</code></td></tr></tbody></table><h3 id="双元音-8" tabindex="-1">双元音（8） <a class="header-anchor" href="#双元音-8" aria-label="Permalink to “双元音（8）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>大致感觉</th><th>例词</th></tr></thead><tbody><tr><td>/eɪ/</td><td>诶到衣</td><td><code>name</code></td></tr><tr><td>/aɪ/</td><td>啊到衣</td><td><code>time</code></td></tr><tr><td>/ɔɪ/</td><td>哦到衣</td><td><code>boy</code></td></tr><tr><td>/əʊ/</td><td>呃到欧</td><td><code>go</code></td></tr><tr><td>/aʊ/</td><td>啊到乌</td><td><code>now</code></td></tr><tr><td>/ɪə/</td><td>衣到呃</td><td><code>here</code></td></tr><tr><td>/eə/</td><td>诶到呃</td><td><code>care</code></td></tr><tr><td>/ʊə/</td><td>乌到呃</td><td><code>tour</code></td></tr></tbody></table><hr><h2 id="二、辅音-28" tabindex="-1">二、辅音（28） <a class="header-anchor" href="#二、辅音-28" aria-label="Permalink to “二、辅音（28）”">​</a></h2><h3 id="爆破音-6" tabindex="-1">爆破音（6） <a class="header-anchor" href="#爆破音-6" aria-label="Permalink to “爆破音（6）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>例词</th></tr></thead><tbody><tr><td>/p/</td><td><code>pen</code></td></tr><tr><td>/b/</td><td><code>big</code></td></tr><tr><td>/t/</td><td><code>tea</code></td></tr><tr><td>/d/</td><td><code>dog</code></td></tr><tr><td>/k/</td><td><code>cat</code></td></tr><tr><td>/g/</td><td><code>go</code></td></tr></tbody></table><h3 id="摩擦音-10" tabindex="-1">摩擦音（10） <a class="header-anchor" href="#摩擦音-10" aria-label="Permalink to “摩擦音（10）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>例词</th></tr></thead><tbody><tr><td>/f/</td><td><code>fine</code></td></tr><tr><td>/v/</td><td><code>very</code></td></tr><tr><td>/θ/</td><td><code>think</code></td></tr><tr><td>/ð/</td><td><code>this</code></td></tr><tr><td>/s/</td><td><code>see</code></td></tr><tr><td>/z/</td><td><code>zoo</code></td></tr><tr><td>/ʃ/</td><td><code>she</code></td></tr><tr><td>/ʒ/</td><td><code>measure</code></td></tr><tr><td>/h/</td><td><code>hello</code></td></tr><tr><td>/r/</td><td><code>red</code></td></tr></tbody></table><h3 id="破擦音-6" tabindex="-1">破擦音（6） <a class="header-anchor" href="#破擦音-6" aria-label="Permalink to “破擦音（6）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>例词</th></tr></thead><tbody><tr><td>/tʃ/</td><td><code>chair</code></td></tr><tr><td>/dʒ/</td><td><code>job</code></td></tr><tr><td>/tr/</td><td><code>tree</code></td></tr><tr><td>/dr/</td><td><code>drive</code></td></tr><tr><td>/ts/</td><td><code>cats</code></td></tr><tr><td>/dz/</td><td><code>beds</code></td></tr></tbody></table><h3 id="鼻音-3" tabindex="-1">鼻音（3） <a class="header-anchor" href="#鼻音-3" aria-label="Permalink to “鼻音（3）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>例词</th></tr></thead><tbody><tr><td>/m/</td><td><code>man</code></td></tr><tr><td>/n/</td><td><code>name</code></td></tr><tr><td>/ŋ/</td><td><code>sing</code></td></tr></tbody></table><h3 id="舌侧音-半元音-3" tabindex="-1">舌侧音 / 半元音（3） <a class="header-anchor" href="#舌侧音-半元音-3" aria-label="Permalink to “舌侧音 / 半元音（3）”">​</a></h3><table tabindex="0"><thead><tr><th>音标</th><th>例词</th></tr></thead><tbody><tr><td>/l/</td><td><code>look</code></td></tr><tr><td>/w/</td><td><code>we</code></td></tr><tr><td>/j/</td><td><code>yes</code></td></tr></tbody></table><hr><h2 id="三、最容易读错的几个音" tabindex="-1">三、最容易读错的几个音 <a class="header-anchor" href="#三、最容易读错的几个音" aria-label="Permalink to “三、最容易读错的几个音”">​</a></h2><h3 id="_1-θ-和-s" tabindex="-1">1. /θ/ 和 /s/ <a class="header-anchor" href="#_1-θ-和-s" aria-label="Permalink to “1. /θ/ 和 /s/”">​</a></h3><ul><li><code>think</code> 不是 <code>sink</code></li><li>舌尖要轻轻碰上齿</li></ul><h3 id="_2-ð-和-z" tabindex="-1">2. /ð/ 和 /z/ <a class="header-anchor" href="#_2-ð-和-z" aria-label="Permalink to “2. /ð/ 和 /z/”">​</a></h3><ul><li><code>this</code> 不是 <code>zis</code></li><li>同样要带“咬舌”动作</li></ul><h3 id="_3-ɪ-和-iː" tabindex="-1">3. /ɪ/ 和 /iː/ <a class="header-anchor" href="#_3-ɪ-和-iː" aria-label="Permalink to “3. /ɪ/ 和 /iː/”">​</a></h3><ul><li><code>ship</code> 和 <code>sheep</code> 要区分长短</li></ul><h3 id="_4-æ-和-e" tabindex="-1">4. /æ/ 和 /e/ <a class="header-anchor" href="#_4-æ-和-e" aria-label="Permalink to “4. /æ/ 和 /e/”">​</a></h3><ul><li><code>bad</code> 和 <code>bed</code> 口型不同，<code>/æ/</code> 张口更大</li></ul><h3 id="_5-ŋ-和-n" tabindex="-1">5. /ŋ/ 和 /n/ <a class="header-anchor" href="#_5-ŋ-和-n" aria-label="Permalink to “5. /ŋ/ 和 /n/”">​</a></h3><ul><li><code>sing</code> 结尾不是普通 <code>n</code></li></ul><hr><h2 id="四、练习建议" tabindex="-1">四、练习建议 <a class="header-anchor" href="#四、练习建议" aria-label="Permalink to “四、练习建议”">​</a></h2><ul><li>每次只练 5-8 个音</li><li>先听标准发音，再跟读</li><li>单词不要只看拼写，要看音标</li><li>把自己容易错的音单独记下来反复练</li></ul><hr><h2 id="五、入门目标" tabindex="-1">五、入门目标 <a class="header-anchor" href="#五、入门目标" aria-label="Permalink to “五、入门目标”">​</a></h2><p>学完这一篇，不要求你一次全记住，但至少要做到：</p><ul><li>看到常见音标不陌生</li><li>知道长短音的大区别</li><li>会分辨几个高频易错音</li><li>为后面背句子模板打下发音基础</li></ul>',39)])])}const _=d(o,[["render",c]]);export{m as __pageData,_ as default};
